create or replace function public.post_supplier_bill(p_organization_id uuid,p_purchase_order_id uuid,p_goods_receipt_id uuid,p_supplier_invoice_number text,p_bill_date date,p_due_date date,p_notes text,p_lines jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare po public.purchase_orders%rowtype; v_id uuid; v_no text; v_journal uuid; v_journal_no text; line jsonb; item public.purchase_order_items%rowtype; v_qty numeric; v_cost numeric; v_tax_rate numeric; v_subtotal numeric:=0; v_tax numeric:=0; v_line_subtotal numeric; v_line_tax numeric; v_inventory uuid; v_expense uuid; v_input_vat uuid; v_ap uuid; v_account uuid; all_billed boolean; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant']::public.app_role[]) then raise exception 'Insufficient accounts payable permission'; end if; select * into po from public.purchase_orders where id=p_purchase_order_id and organization_id=p_organization_id for update; if not found or po.status not in ('partially_received','received','billed') then raise exception 'Purchase order must be received before billing'; end if; if p_goods_receipt_id is not null and not exists(select 1 from public.goods_receipts where id=p_goods_receipt_id and purchase_order_id=po.id and organization_id=p_organization_id and status='posted') then raise exception 'Goods receipt not found'; end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)=0 then raise exception 'Supplier bill requires lines'; end if; select id into v_inventory from public.accounts where organization_id=p_organization_id and code='1200'; select id into v_expense from public.accounts where organization_id=p_organization_id and code='6000'; select id into v_input_vat from public.accounts where organization_id=p_organization_id and code='1300'; select id into v_ap from public.accounts where organization_id=p_organization_id and code='2000'; if v_inventory is null or v_expense is null or v_input_vat is null or v_ap is null then raise exception 'Required purchasing accounts are missing'; end if; v_no:=public.next_document_number(p_organization_id,'BILL'); v_journal_no:=public.next_document_number(p_organization_id,'JE'); insert into public.journal_entries(organization_id,branch_id,entry_number,entry_date,memo,status,source_type,created_by) values(p_organization_id,po.branch_id,v_journal_no,coalesce(p_bill_date,current_date),'Supplier bill '||v_no,'draft','supplier_bill',p_actor_id) returning id into v_journal; insert into public.supplier_bills(organization_id,branch_id,supplier_id,purchase_order_id,goods_receipt_id,bill_number,supplier_invoice_number,bill_date,due_date,status,notes,journal_entry_id,created_by,posted_at) values(p_organization_id,po.branch_id,po.supplier_id,po.id,p_goods_receipt_id,v_no,nullif(trim(p_supplier_invoice_number),''),coalesce(p_bill_date,current_date),coalesce(p_due_date,coalesce(p_bill_date,current_date)),'posted',nullif(trim(p_notes),''),v_journal,p_actor_id,now()) returning id into v_id; for line in select value from jsonb_array_elements(p_lines) loop select * into item from public.purchase_order_items where id=(line->>'purchaseOrderItemId')::uuid and purchase_order_id=po.id and organization_id=p_organization_id for update; if not found then raise exception 'Purchase order line not found'; end if; v_qty:=coalesce((line->>'quantity')::numeric,0); v_cost:=coalesce(nullif(line->>'unitCost','')::numeric,item.unit_cost); v_tax_rate:=coalesce(nullif(line->>'taxRate','')::numeric,item.tax_rate); if v_qty<=0 or item.billed_quantity+v_qty>item.received_quantity or v_cost<0 or v_tax_rate<0 or v_tax_rate>100 then raise exception 'Invalid billed quantity or amount'; end if; v_line_subtotal:=round(v_qty*v_cost,2); v_line_tax:=round(v_line_subtotal*v_tax_rate/100,2); v_subtotal:=v_subtotal+v_line_subtotal; v_tax:=v_tax+v_line_tax; v_account:=case when item.product_id is not null then v_inventory else coalesce(nullif(line->>'expenseAccountId','')::uuid,v_expense) end; if not exists(select 1 from public.accounts where id=v_account and organization_id=p_organization_id and is_active) then raise exception 'Invalid expense account'; end if; insert into public.supplier_bill_items(organization_id,supplier_bill_id,purchase_order_item_id,product_id,description,quantity,unit_cost,tax_rate,line_subtotal,line_tax,expense_account_id) values(p_organization_id,v_id,item.id,item.product_id,item.description,v_qty,v_cost,v_tax_rate,v_line_subtotal,v_line_tax,v_account); insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,v_account,item.description,v_line_subtotal,0); update public.purchase_order_items set billed_quantity=billed_quantity+v_qty where id=item.id; end loop; if v_tax>0 then insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,v_input_vat,'Input VAT',v_tax,0); end if; insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,v_ap,'Accounts payable',0,v_subtotal+v_tax); update public.supplier_bills set subtotal=v_subtotal,tax_amount=v_tax where id=v_id; update public.journal_entries set status='posted',source_id=v_id,posted_by=p_actor_id,posted_at=now() where id=v_journal; select bool_and(billed_quantity>=received_quantity and received_quantity>0) into all_billed from public.purchase_order_items where purchase_order_id=po.id; if all_billed then update public.purchase_orders set status='billed',updated_at=now() where id=po.id; end if; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.bill.posted','supplier_bill',v_id,jsonb_build_object('number',v_no,'total',v_subtotal+v_tax,'journal',v_journal)); return jsonb_build_object('id',v_id,'number',v_no,'total',v_subtotal+v_tax); end $$;

create or replace function public.record_supplier_payment(p_organization_id uuid,p_supplier_bill_id uuid,p_amount numeric,p_method text,p_payment_date date,p_reference text,p_notes text,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare b public.supplier_bills%rowtype; s public.suppliers%rowtype; v_cash uuid; v_ap uuid; v_payment_no text; v_payment_id uuid; v_outstanding numeric; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant']::public.app_role[]) then raise exception 'Insufficient accounts payable permission'; end if; select * into b from public.supplier_bills where id=p_supplier_bill_id and organization_id=p_organization_id for update; if not found or b.status not in ('posted','partially_paid') then raise exception 'Open supplier bill not found'; end if; select * into s from public.suppliers where id=b.supplier_id and organization_id=p_organization_id; v_outstanding:=b.total-b.credited_amount-b.paid_amount; if p_amount<=0 or p_amount>v_outstanding then raise exception 'Payment exceeds supplier bill balance'; end if; select id into v_cash from public.accounts where organization_id=p_organization_id and code='1000'; select id into v_ap from public.accounts where organization_id=p_organization_id and code='2000'; v_payment_no:=public.record_finance_payment(p_organization_id,b.branch_id,'payment',p_amount,0,coalesce(nullif(trim(p_method),''),'cash'),coalesce(p_payment_date,current_date),v_cash,v_ap,null,null,null,s.name,p_reference,p_notes,p_actor_id); select id into v_payment_id from public.payments where organization_id=p_organization_id and payment_number=v_payment_no; insert into public.supplier_bill_payments(organization_id,supplier_bill_id,payment_id,amount) values(p_organization_id,b.id,v_payment_id,p_amount); update public.supplier_bills set paid_amount=paid_amount+p_amount,status=case when paid_amount+p_amount>=total-credited_amount then 'paid' else 'partially_paid' end where id=b.id; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.bill.paid','supplier_bill',b.id,jsonb_build_object('number',b.bill_number,'payment',v_payment_no,'amount',p_amount)); return jsonb_build_object('id',v_payment_id,'number',v_payment_no,'amount',p_amount); end $$;

create or replace function public.post_purchase_return(p_organization_id uuid,p_purchase_order_id uuid,p_supplier_bill_id uuid,p_return_date date,p_reason text,p_lines jsonb,p_actor_id uuid) returns jsonb language plpgsql security definer set search_path='' as $$ declare po public.purchase_orders%rowtype; b public.supplier_bills%rowtype; v_id uuid; v_no text; v_journal uuid; v_journal_no text; line jsonb; item public.purchase_order_items%rowtype; v_qty numeric; v_warehouse uuid; v_subtotal numeric:=0; v_tax numeric:=0; v_line_subtotal numeric; v_line_tax numeric; v_inventory uuid; v_input_vat uuid; v_ap uuid; begin if p_actor_id is distinct from auth.uid() then raise exception 'Actor mismatch'; end if; if not public.has_org_role(p_organization_id,array['owner','admin','accountant','inventory']::public.app_role[]) then raise exception 'Insufficient purchase return permission'; end if; select * into po from public.purchase_orders where id=p_purchase_order_id and organization_id=p_organization_id for update; if not found then raise exception 'Purchase order not found'; end if; select * into b from public.supplier_bills where id=p_supplier_bill_id and purchase_order_id=po.id and organization_id=p_organization_id for update; if not found or b.status='void' then raise exception 'Supplier bill not found'; end if; if jsonb_typeof(p_lines)<>'array' or jsonb_array_length(p_lines)=0 then raise exception 'Return requires lines'; end if; select id into v_inventory from public.accounts where organization_id=p_organization_id and code='1200'; select id into v_input_vat from public.accounts where organization_id=p_organization_id and code='1300'; select id into v_ap from public.accounts where organization_id=p_organization_id and code='2000'; v_no:=public.next_document_number(p_organization_id,'PRET'); v_journal_no:=public.next_document_number(p_organization_id,'JE'); insert into public.journal_entries(organization_id,branch_id,entry_number,entry_date,memo,status,source_type,created_by) values(p_organization_id,po.branch_id,v_journal_no,coalesce(p_return_date,current_date),'Purchase return '||v_no,'draft','purchase_return',p_actor_id) returning id into v_journal; insert into public.purchase_returns(organization_id,branch_id,supplier_id,purchase_order_id,supplier_bill_id,return_number,return_date,status,reason,journal_entry_id,created_by,posted_at) values(p_organization_id,po.branch_id,po.supplier_id,po.id,b.id,v_no,coalesce(p_return_date,current_date),'posted',nullif(trim(p_reason),''),v_journal,p_actor_id,now()) returning id into v_id; for line in select value from jsonb_array_elements(p_lines) loop select * into item from public.purchase_order_items where id=(line->>'purchaseOrderItemId')::uuid and purchase_order_id=po.id and organization_id=p_organization_id for update; if not found or item.product_id is null then raise exception 'Purchase order product line not found'; end if; v_qty:=coalesce((line->>'quantity')::numeric,0); v_warehouse:=coalesce(nullif(line->>'warehouseId','')::uuid,item.warehouse_id); if v_qty<=0 or item.returned_quantity+v_qty>item.received_quantity or v_warehouse is null then raise exception 'Invalid return quantity'; end if; v_line_subtotal:=round(v_qty*item.unit_cost,2); v_line_tax:=round(v_line_subtotal*item.tax_rate/100,2); v_subtotal:=v_subtotal+v_line_subtotal; v_tax:=v_tax+v_line_tax; perform public.record_stock_movement(p_organization_id,item.product_id,v_warehouse,'return_out',v_qty,v_no,p_actor_id,'purchase_return',v_id); insert into public.purchase_return_items(organization_id,purchase_return_id,purchase_order_item_id,product_id,warehouse_id,quantity,unit_cost,tax_rate,line_subtotal,line_tax) values(p_organization_id,v_id,item.id,item.product_id,v_warehouse,v_qty,item.unit_cost,item.tax_rate,v_line_subtotal,v_line_tax); update public.purchase_order_items set returned_quantity=returned_quantity+v_qty where id=item.id; end loop; insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,v_ap,'Supplier credit',v_subtotal+v_tax,0),(p_organization_id,v_journal,v_inventory,'Inventory returned',0,v_subtotal); if v_tax>0 then insert into public.journal_lines(organization_id,journal_entry_id,account_id,description,debit,credit) values(p_organization_id,v_journal,v_input_vat,'Input VAT reversed',0,v_tax); end if; update public.purchase_returns set subtotal=v_subtotal,tax_amount=v_tax where id=v_id; update public.supplier_bills set credited_amount=credited_amount+v_subtotal+v_tax,status=case when paid_amount>=total-(credited_amount+v_subtotal+v_tax) then 'credited' else status end where id=b.id; update public.journal_entries set status='posted',source_id=v_id,posted_by=p_actor_id,posted_at=now() where id=v_journal; insert into public.audit_events(organization_id,actor_id,action,entity_type,entity_id,metadata) values(p_organization_id,p_actor_id,'purchasing.return.posted','purchase_return',v_id,jsonb_build_object('number',v_no,'total',v_subtotal+v_tax)); return jsonb_build_object('id',v_id,'number',v_no,'total',v_subtotal+v_tax); end $$;

revoke all on function public.post_supplier_bill(uuid,uuid,uuid,text,date,date,text,jsonb,uuid) from public; grant execute on function public.post_supplier_bill(uuid,uuid,uuid,text,date,date,text,jsonb,uuid) to authenticated;
revoke all on function public.record_supplier_payment(uuid,uuid,numeric,text,date,text,text,uuid) from public; grant execute on function public.record_supplier_payment(uuid,uuid,numeric,text,date,text,text,uuid) to authenticated;
revoke all on function public.post_purchase_return(uuid,uuid,uuid,date,text,jsonb,uuid) from public; grant execute on function public.post_purchase_return(uuid,uuid,uuid,date,text,jsonb,uuid) to authenticated;